import React from "react";
import "./Carousel.css";

const Carousel = (props) => {

  const buttons = (images) => {
    const btn=[];
      for (let index = 1; index < images.length; index++) {
        btn.push(<button type="button" data-bs-target={"#carousel"+props.image+props.id} data-bs-slide-to={index} className="btn-dot" aria-label={"Slide "+index}></button>)
        
      }
      return btn;
  }


  const images = (images)=>{

    const image=[];
    for (let index = 1; index < images.length; index++) {
      image.push(
        <div className="carousel-item">
        <img src={require(`../../assets/images/${images[index]}`)} className="d-block w-100" alt="..." loading="lazy"/>
      </div>
      )
      
    }
    return image;

  }
  return (
    <div id={`${"carousel"+props.type+props.id}`}  className="carousel slide">
      <div className="carousel-indicators">
        <button type="button" data-bs-target={"#carousel"+props.image+props.id}  data-bs-slide-to="0" className="btn-dot active" aria-current="true" aria-label="Slide 0"></button>
          {buttons(props.images)}
        
      </div>
      <div className="carousel-inner">
      <div className="carousel-item active">
              <img src={require(`../../assets/images/${props.images[0]}`)} className="d-block w-100" alt="..." loading="lazy" />
            </div>
    {images(props.images)}
      </div>
      <button className="carousel-control-prev" type="button" data-bs-target={`${"#carousel"+props.type+props.id}`} data-bs-slide="prev">
        <span className="carousel-control-prev-icon" aria-hidden="true"></span>
        <span className="visually-hidden">Previous</span>
      </button>
      <button className="carousel-control-next" type="button" data-bs-target={`${"#carousel"+props.type+props.id}`} data-bs-slide="next">
        <span className="carousel-control-next-icon" aria-hidden="true"></span>
        <span className="visually-hidden">Next</span>
      </button>
    </div>
  );
};

export default Carousel;
