import React from "react";
import Modal from "./Modal";

import "./Work.css";
import WorkDataExterior from "../../data/WorkDataExterior";
import WorkDataInterior from "../../data/WorkDataInterior";
import Item from "./Item";

const Work = () => {

const itemsExterior = WorkDataExterior.map(item =>{
return <Item key={item.id} id={item.id} image={item.mainImage} region={item.region} description={item.description}  type={item.type}/>
})
const modalsExterior = WorkDataExterior.map(item =>{
return <Modal key={item.id} id={item.id} images={item.images} description={item.description} type={item.type}/>
})
const itemsInterior = WorkDataInterior.map(item =>{
return <Item key={item.id} id={item.id} image={item.mainImage} region={item.region} description={item.description}  type={item.type}/>
})
const modalsInterior = WorkDataInterior.map(item =>{
return <Modal key={item.id} id={item.id} images={item.images} description={item.description} type={item.type}/>
})




  return (
    <section id="two">
      <h2>Exterior Work</h2>
      <div className="row">

        {itemsExterior}
      </div>
      {modalsExterior}
      <hr/>
      <h2>Interior Work</h2>
      <div className="row">
        {itemsInterior}
      </div>
      {modalsInterior}
    </section>
  );
};

export default Work;
